class Solution {
    public int[] pivotArray(int[] nums, int pivot) {
        int[] result = new int[nums.length];
        int left = 0, middle = 0, right = nums.length - 1;

        // Partition elements into three parts: less than pivot, equal to pivot, and greater than pivot
        while (middle <= right) {
            if (nums[middle] < pivot) {
                // Swap elements at left and middle indices if middle element is less than pivot
                int temp = nums[left];
                nums[left] = nums[middle];
                nums[middle] = temp;
                left++;
                middle++;
            } else if (nums[middle] > pivot) {
                // Swap elements at middle and right indices if middle element is greater than pivot
                int temp = nums[middle];
                nums[middle] = nums[right];
                nums[right] = temp;
                right--;
            } else {
                // If middle element is equal to pivot, move to the next element
                middle++;
            }
        }
        return nums;
    }
}
